mapper.select:
SELECT version, reason, lastUpdateDtime, lastUpdateUserId, titleKo, contentKo, titleEn, contentEn, closeableYn, hideTodayYn FROM ( SELECT a.*, ROWNUM AS rnum FROM ( SELECT h_use.VERSION AS version, h_use.REASON AS reason, h_use.LAST_UPDATE_DTIME AS lastUpdateDtime, h_use.LAST_UPDATE_USER_ID AS lastUpdateUserId, h_ko.PROPERTY_DESC AS titleKo, h_ko.DEFAULT_VALUE AS contentKo, h_en.PROPERTY_DESC AS titleEn, h_en.DEFAULT_VALUE AS contentEn, h_cl.DEFAULT_VALUE AS closeableYn, h_ht.DEFAULT_VALUE AS hideTodayYn FROM FWK_PROPERTY_HISTORY h_use LEFT JOIN FWK_PROPERTY_HISTORY h_ko ON h_ko.PROPERTY_GROUP_ID = 'notice' AND h_ko.PROPERTY_ID = 'EMERGENCY_KO' AND h_ko.VERSION = h_use.VERSION LEFT JOIN FWK_PROPERTY_HISTORY h_en ON h_en.PROPERTY_GROUP_ID = 'notice' AND h_en.PROPERTY_ID = 'EMERGENCY_EN' AND h_en.VERSION = h_use.VERSION LEFT JOIN FWK_PROPERTY_HISTORY h_cl ON h_cl.PROPERTY_GROUP_ID = 'notice' AND h_cl.PROPERTY_ID = 'CLOSEABLE_YN' AND h_cl.VERSION = h_use.VERSION LEFT JOIN FWK_PROPERTY_HISTORY h_ht ON h_ht.PROPERTY_GROUP_ID = 'notice' AND h_ht.PROPERTY_ID = 'HIDE_TODAY_YN' AND h_ht.VERSION = h_use.VERSION WHERE h_use.PROPERTY_GROUP_ID = 'notice' AND h_use.PROPERTY_ID = 'USE_YN'
AND h_use.REASON = #{reason}
ORDER BY h_use.VERSION DESC ) a WHERE ROWNUM <= #{offset} + #{pageSize} ) WHERE rnum > #{offset}
